import React from "react";
import logo from "../images/plane.png"
import "../styles/Welcome.css";

function Welcome(){
    return(
        <>
            <img src={logo} alt="cielo" />
            <div><p>Find 
            your perfect trip, designed by insiders who know and love 
            their cities!</p></div>
        </>
    );
}
export default Welcome;
